const input = $input.item.json.body;

const phaseInfo = {
  engage: {
    label: 'Engage (引入)',
    description: '建立情感连接与情境导入，激发好奇心和参与动机',
    stepCount: 1,
    timeRatio: '15%'
  },
  empower: {
    label: 'Empower (赋能)',
    description: '输入语言知识与SEL技能，进行体感探索',
    stepCount: 2,
    timeRatio: '40%'
  },
  execute: {
    label: 'Execute (实践)',
    description: '通过艺术表达完成终极产出任务，体验合作分享',
    stepCount: 2,
    timeRatio: '30%'
  },
  elevate: {
    label: 'Elevate (升华)',
    description: '反思、内化并建立积极情绪闭环',
    stepCount: 1,
    timeRatio: '15%'
  }
};

const phaseKey = input.phaseKey || 'engage';
const info = phaseInfo[phaseKey];

let otherPhasesStr = '无';
if (input.currentCourseData) {
  try {
    const courseData = typeof input.currentCourseData === 'string' 
      ? JSON.parse(input.currentCourseData) 
      : input.currentCourseData;
    const otherPhases = {};
    for (const [key, value] of Object.entries(courseData)) {
      if (key !== phaseKey && key !== 'courseOverview') {
        otherPhases[key] = { title: value.title, steps: value.steps };
      }
    }
    otherPhasesStr = JSON.stringify(otherPhases, null, 2);
  } catch (e) {
    otherPhasesStr = '无法解析';
  }
}

return {
  age: input.age || '7-9岁',
  duration: input.duration || '60分钟',
  scale: input.scale || '≤ 8人',
  title: input.title || '未命名课件',
  vocabulary: (input.vocabulary && input.vocabulary.length > 0) 
    ? (Array.isArray(input.vocabulary) ? input.vocabulary.join(', ') : input.vocabulary)
    : '请根据主题推荐词汇',
  grammar: (input.grammar && input.grammar.length > 0) 
    ? (Array.isArray(input.grammar) ? input.grammar.join(', ') : input.grammar)
    : '请根据主题推荐句型',
  theme: input.theme || '默认主题',
  requirements: input.requirements || '',
  phaseKey: phaseKey,
  phaseLabel: info.label,
  phaseDescription: info.description,
  stepCount: info.stepCount,
  timeRatio: info.timeRatio,
  otherPhases: otherPhasesStr
};
